#[test]
fn test_phonon_kpoints_mp_grid_from_cell_value() {
    let val = CellValue::Array(vec![
        CellValue::UInt(4),
        CellValue::UInt(4),
        CellValue::UInt(4),
    ]);
    let grid = PhononKpointsMpGrid::from_cell_value(&val).unwrap();
    assert_eq!(grid.0, [4, 4, 4]);
}

#[test]
fn test_phonon_kpoints_mp_spacing_scalar() {
    let value = CellValue::Float(0.1);
    let result = PhononKpointsMpSpacing::from_cell_value(&value).unwrap();
    assert_eq!(result.value, 0.1);
    assert_eq!(result.unit, None);
}

#[test]
fn test_phonon_kpoints_mp_offset_from_cell_value() {
