        CellValue::Float(0.0),
        CellValue::Float(0.0),
        CellValue::Float(0.0),
    ]);
    let offset = PhononKpointsMpOffset::from_cell_value(&val).unwrap();
    assert_eq!(offset.0, [0.0, 0.0, 0.0]);
}

#[test]
fn test_phonon_fine_kpoint_path_multiple_entries() {
    let rows = vec![
        CellValue::Array(vec![
            CellValue::Float(0.0),
            CellValue::Float(0.0),
            CellValue::Float(0.0),
        ]),
        CellValue::Array(vec![
            CellValue::Float(0.5),
            CellValue::Float(0.5),
            CellValue::Float(0.5),
        ]),
    ];
    let result = PhononFineKpointPath::from_block_rows(&rows).unwrap();
    assert_eq!(result.points.len(), 2);
    assert_eq!(result.points[0].coord, [0.0, 0.0, 0.0]);
}

#[test]
fn test_phonon_fine_kpoint_path_spacing_with_unit() {
    let value = CellValue::Array(vec![
        CellValue::Float(0.05),
        CellValue::Str("1/ang"),
    ]);
    let result = PhononFineKpointPathSpacing::from_cell_value(&value).unwrap();
    assert_eq!(result.value, 0.05);
    assert!(result.unit.is_some());
}

